import heapq

class MedianFinder:
    def __init__(self):
        self.low = []
        self.high = []

    def addNum(self, num):
        heapq.heappush(self.low, -num)
        heapq.heappush(self.high, -heapq.heappop(self.low))
        if len(self.high) > len(self.low):
            heapq.heappush(self.low, -heapq.heappop(self.high))

    def findMedian(self):
        if len(self.low) > len(self.high):
            return -self.low[0]
        return (-self.low[0] + self.high[0]) / 2

class Solution:
    def medianFinder(self, operations, values):
        obj = None
        out = []
        for op, args in zip(operations, values):
            if op == 'MedianFinder':
                obj = MedianFinder()
            elif op == 'addNum':
                obj.addNum(args[0])
            elif op == 'findMedian':
                out.append(obj.findMedian())
        return out
